-- Safe XML parsing function with XXE protection
local function parse_xml_safely(xml_string)
    if not xml_string or xml_string == "" then
        return nil, "Empty XML body"
    end
    
    -- Strip XML declaration and DOCTYPE to prevent XXE
    xml_string = xml_string:gsub("<%?xml[^%?>]*%?>", "")
    xml_string = xml_string:gsub("<!DOCTYPE[^>]*>", "")
    xml_string = xml_string:gsub("<!DOCTYPE[^%[]*%[[^%]]*%][^>]*>", "")
    
    local success, result = pcall(function()
        return xml.load(xml_string)
    end)
    
    if not success then
        return nil, "XML parsing failed: " .. tostring(result)
    end
    
    return result, nil
end

-- Extract text content from XML node
local function get_node_text(node)
    if type(node) == "string" then
        return node
    elseif type(node) == "table" then
        if node[1] then
            return get_node_text(node[1])
        end
    end
    return ""
end

-- Find node by tag name
local function find_node(root, tag_name)
    if not root then return nil end
    
    if type(root) == "table" then
        if root._name == tag_name then
            return root
        end
        
        for _, child in ipairs(root) do
            local found = find_node(child, tag_name)
            if found then return found end
        end
    end
    
    return nil
end

-- Extract all nodes with specific tag
local function find_all_nodes(root, tag_name, results)
    results = results or {}
    
    if not root then return results end
    
    if type(root) == "table" then
        if root._name == tag_name then
            table.insert(results, root)
        end
        
        for _, child in ipairs(root) do
            find_all_nodes(child, tag_name, results)
        end
    end
    
    return results
end

